const data = $json;

const policies = data.Policies || [];
const requestBody = data.body || {};

const id = requestBody.insurance_id;
const symptoms = requestBody.symptoms;
const hospital = requestBody.hospital;

const patient = policies.find(p => p.insurance_id === id);

if (!patient) {
  return [
    {
      json: {
        ...data,
        patient_found: false,
        policy_valid: false,
        error: "Paciente no encontrado",
        searched_insurance_id: id || null
      }
    }
  ];
}

return [
  {
    json: {
      ...data,
      patient_found: true,
      selected_policy: patient,
      insurance_id: patient.insurance_id,
      patient_name: patient.patient_name,
      active: patient.active,
      plan: patient.plan,
      coverage_level: patient.coverage_level,
      coverage_start: patient.coverage_start,
      coverage_end: patient.coverage_end,
      emergency_coverage: patient.emergency_coverage,
      deductible_remaining: patient.deductible_remaining,
      status: patient.status,
      symptoms,
      hospital
    }
  }
];

const policy = $('Policies_Json').first().json.Policies;
const pacient = $('Buscar paciente por insurance_id').first().json;
const today = new Date();

// Verificaciones
if (pacient.active !== true) {
  return [
    {
      json: {
        ...pacient,
        policy_valid: false,
        reason: "La póliza no está activa"
      }
    }
  ];
} else if (pacient.status !== "Active") {
  return [
    {
      json: {
        ...pacient,
        policy_valid: false,
        reason: `El estado de la póliza es '${pacient.status}'`
      }
    }
  ];
} else if (new Date(pacient.coverage_end) <= today) {
  return [
    {
      json: {
        ...pacient,
        policy_valid: false,
        reason: "La póliza ha expirado"
      }
    }
  ];
}

// Si todo está OK, devolver solo paciente + datos originales
return [
  {
    json: {
      ...pacient
    }
  }
];

const medicalHistory = $('Medical_History_Json').first().json.medical_history;

// Buscar historial por insurance_id
// viene del Webhook

const patientId = String($('Webhook').first().json.insurance_id).trim();

// 3️⃣ Filtrar todas las visitas de ese paciente
const patientHistory = medicalHistory.filter(record => 
  String(record.insurance_id).trim() === patientId
);
// Devolver resultado: si no hay historial, devolver array vacío
return [
  {
    json: {
      ...$('Validación base de póliza').first().json,
      //id: patientId,
      history: patientHistory ? patientHistory : [],
      //medicalHistory: medicalHistory
    }
  }
];

const content = $json.message.content;

return {...$('Buscar historial médico by insurance_id').first().json,json_IA: JSON.parse(content) }
;

