const data = $json;

// fecha actual
const today = new Date();

// fecha fin de cobertura
const coverageEnd = new Date(data.coverage_end);

let policy_valid = true;
let policy_error = null;

// validar póliza activa
if (!data.active) {
  policy_valid = false;
  policy_error = "Póliza inactiva";
}

// validar estado de póliza
if (data.status !== "Active") {
  policy_valid = false;
  policy_error = "Estado de póliza inválido";
}

// validar fecha de cobertura
if (coverageEnd < today) {
  policy_valid = false;
  policy_error = "Cobertura expirada";
}

// retorno final
return [
  {
    json: {
      ...data,
      policy_valid,
      policy_error
    }
  }
];

const data = $json;

// historial completo
const medicalHistory = data.medical_history || [];

// insurance_id del paciente actual
const insuranceId = data.insurance_id;

// filtrar historial
const patientHistory = medicalHistory.filter(
  h => h.insurance_id === insuranceId
);

// ordenar por fecha más reciente
patientHistory.sort((a, b) => 
  new Date(b.visit_date) - new Date(a.visit_date)
);

return [
  {
    json: {
      ...data,
      patient_medical_history: patientHistory,
      emergency_visits: patientHistory.filter(
        h => h.visit_type === "Emergency"
      ),
      total_history_records: patientHistory.length
    }
  }
];

const data = $json;

const symptoms = (data.symptoms || "").toLowerCase();

let risk_score = 0;
let priority = "LOW";
let alerts = [];


if (
  symptoms.includes("dolor de pecho") ||
  symptoms.includes("pecho")
) {
  risk_score += 40;
  alerts.push("Posible problema cardíaco");
}

if (
  symptoms.includes("dificultad para respirar") ||
  symptoms.includes("respirar")
) {
  risk_score += 35;
  alerts.push("Problema respiratorio");
}

if (
  symptoms.includes("desmayo") ||
  symptoms.includes("convulsión")
) {
  risk_score += 50;
  alerts.push("Evento neurológico crítico");
}

if (
  symptoms.includes("sangrado")
) {
  risk_score += 30;
  alerts.push("Posible hemorragia");
}


const history = data.patient_medical_history || [];

history.forEach(record => {

  const condition = (record.condition || "").toLowerCase();
  const severity = (record.severity || "").toLowerCase();

  if (severity === "alta") {
    risk_score += 15;
  }

  if (
    condition.includes("hipertensión") ||
    condition.includes("card")
  ) {
    risk_score += 20;
    alerts.push("Antecedente cardiovascular");
  }

  if (
    condition.includes("asma")
  ) {
    risk_score += 15;
    alerts.push("Antecedente respiratorio");
  }

  if (
    condition.includes("diabetes")
  ) {
    risk_score += 10;
    alerts.push("Paciente diabético");
  }

});


const emergencyVisits = data.emergency_visits || [];

if (emergencyVisits.length >= 1) {
  risk_score += 20;
  alerts.push("Historial de emergencias");
}

if (emergencyVisits.length >= 3) {
  risk_score += 30;
  alerts.push("Frecuentes emergencias");
}


if (risk_score >= 80) {
  priority = "CRITICAL";
}
else if (risk_score >= 60) {
  priority = "HIGH";
}
else if (risk_score >= 30) {
  priority = "MEDIUM";
}

return [
  {
    json: {
      ...data,

      risk_score,
      priority,
      alerts,

      ai_ready_summary: {
        patient: data.patient_name,
        symptoms: data.symptoms,
        priority,
        risk_score,
        alerts,
        emergency_history_count: emergencyVisits.length
      }
    }
  }
];

const data = $json;


const hospitals = Array.isArray(data.hospitals) ? data.hospitals : [];

const priority = data.priority;
const coverage = data.coverage_level;
const requestedHospitalName = data.hospital;


let availableHospitals = hospitals.filter(h =>
  h.emergency_available === true &&
  h.capacity_status !== "Full"
);


if (coverage === "Premium") {
  const premiumHospitals = availableHospitals.filter(
    h => h.network_level === "Premium"
  );

  if (premiumHospitals.length > 0) {
    availableHospitals = premiumHospitals;
  }
}


const requestedHospital = availableHospitals.find(
  h => h.hospital_name === requestedHospitalName
);

if (requestedHospital) {
  availableHospitals = [
    requestedHospital,
    ...availableHospitals.filter(
      h => h.hospital_name !== requestedHospitalName
    )
  ];
}

if (priority === "CRITICAL") {
  availableHospitals.sort((a, b) => {
    if (a.hospital_name === requestedHospitalName) return -1;
    if (b.hospital_name === requestedHospitalName) return 1;

    return a.estimated_cost_index - b.estimated_cost_index;
  });
} else if (priority === "HIGH") {
  const capacityOrder = {
    "Available": 1,
    "Busy": 2,
    "Full": 3
  };

  availableHospitals.sort((a, b) => {
    if (a.hospital_name === requestedHospitalName) return -1;
    if (b.hospital_name === requestedHospitalName) return 1;

    return capacityOrder[a.capacity_status] -
      capacityOrder[b.capacity_status];
  });
} else {
  availableHospitals.sort((a, b) => {
    if (a.hospital_name === requestedHospitalName) return -1;
    if (b.hospital_name === requestedHospitalName) return 1;

    return a.estimated_cost_index - b.estimated_cost_index;
  });
}

// Hospital seleccionado
const recommendedHospital =
  availableHospitals.length > 0
    ? availableHospitals[0]
    : null;

// Respuesta final del nodo
return [
  {
    json: {
      ...data,

      recommended_hospital: recommendedHospital,

      hospital_recommendation_summary: recommendedHospital
        ? {
            hospital_name: recommendedHospital.hospital_name,
            specialty: recommendedHospital.specialty,
            network_level: recommendedHospital.network_level,
            capacity_status: recommendedHospital.capacity_status,
            emergency_available: recommendedHospital.emergency_available,
            estimated_cost_index: recommendedHospital.estimated_cost_index,
            reason: `Hospital recomendado por prioridad ${priority}, cobertura ${coverage} y disponibilidad de emergencia.`
          }
        : {
            error: "No hay hospitales disponibles para emergencia."
          }
    }
  }
];

