const data = $json;

const hospitalNotification = {

    notification_sent: true,

    target_department: "Admisiones Emergencia",

    hospital:
        data.notifications.hospital.hospital_name,

    priority:
        data.ai_analysis.urgency,

    message:
        data.notifications.hospital.message,

    generated_at:
        new Date().toISOString(),

    admission_case: {

        patient_policy:
            data.patient_summary.insurance_id,

        specialty:
            data.patient_summary.specialty,

        triage_color:
            data.triage_color,

        workflow_status:
            data.workflow_status
    }
};

return [
    {
        json: {

            ...data,

            hospital_notification_result:
                hospitalNotification
        }
    }
];

const data = $json;

let rawResponse = data.response || "";


rawResponse = rawResponse
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

const firstBrace = rawResponse.indexOf("{");
const lastBrace = rawResponse.lastIndexOf("}");

if (firstBrace !== -1 && lastBrace !== -1) {

    rawResponse = rawResponse.substring(
        firstBrace,
        lastBrace + 1
    );
}


let aiParsed = {};

try {

    aiParsed = JSON.parse(rawResponse);

} catch (error) {

    aiParsed = {

        case_status: "error",

        urgency: "UNKNOWN",

        recommended_specialty: "No definida",

        recommended_hospital: "No asignado",

        requires_emergency: false,

        reason:
            "No se pudo interpretar respuesta IA",

        administrative_action:
            "Revisión manual requerida",

        raw_response:
            rawResponse
    };
}

const specialty =
    aiParsed.recommended_specialty || "No definida";

const hospital =
    aiParsed.recommended_hospital || "No asignado";

const urgency =
    aiParsed.urgency || "UNKNOWN";


let triageColor = "GREEN";

if (urgency === "CRITICAL") {

    triageColor = "RED";

}
else if (urgency === "HIGH") {

    triageColor = "ORANGE";

}
else if (urgency === "MEDIUM") {

    triageColor = "YELLOW";
}

const webhookData =
    $node["Webhook"].json.body;


return [
    {
        json: {

            processed_at:
                new Date().toISOString(),

            workflow_status:
                "PROCESSED",

            triage_color:
                triageColor,

            ai_analysis: {

                ...aiParsed,

                specialty:
                    specialty,

                hospital:
                    hospital
            },

            patient_summary: {

                insurance_id:
                    webhookData.insurance_id,

                urgency:
                    urgency,

                recommended_hospital:
                    hospital,

                specialty:
                    specialty
            },

            notifications: {

                hospital: {

                    send: true,

                    hospital_name:
                        hospital,

                    message:
                        `ALERTA ${urgency}: paciente requiere atención en ${specialty}`
                },

                insurance: {

                    send: true,

                    provider:
                        "Plan Oro",

                    policy_number:
                        webhookData.insurance_id,

                    message:
                        `Caso crítico detectado para póliza ${webhookData.insurance_id}`
                }
            },

            full_ai_response:
                aiParsed
        }
    }
];

const data = $json;

const ai = data.ai_analysis || {};

const hospitalNotification =
  data.hospital_notification_result || {};

const insuranceNotification =
